package com.devpro.ard_58_nguyenminhhuan_day07.adapter;import android.view.LayoutInflater;import android.view.View;import android.view.ViewGroup;import android.widget.CheckBox;import android.widget.ImageView;import android.widget.TextView;import androidx.annotation.NonNull;import androidx.recyclerview.widget.RecyclerView;import com.devpro.ard_58_nguyenminhhuan_day07.R;import com.devpro.ard_58_nguyenminhhuan_day07.model.itemFood;import java.util.List;public class ItemFoodAdapter extends RecyclerView.Adapter<ItemFoodAdapter.ItemFoodViewHolder> {    List<itemFood> itemFoods;    private OnFoodListener listener;    public interface OnFoodListener{        void onFoodClick(itemFood itemFood);    }    public ItemFoodAdapter(List<itemFood> itemFoods, OnFoodListener listener){        this.itemFoods = itemFoods;        this.listener = listener;    }    @NonNull    @Override    public ItemFoodAdapter.ItemFoodViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {        return new ItemFoodViewHolder(LayoutInflater.from(parent.getContext()).inflate(R.layout.item_food, parent, false));    }    @Override    public void onBindViewHolder(@NonNull ItemFoodAdapter.ItemFoodViewHolder holder, int position) {        itemFood itemFood = itemFoods.get(position);        holder.imageView.setImageResource(itemFood.getImage());        holder.tvName.setText(itemFood.getName());        holder.tvRate.setText(String.valueOf(itemFood.getRate()));        holder.tvTime.setText(itemFood.getTimeFinish());        holder.cbFavourite.setChecked(itemFood.isFavourite());        holder.itemView.setOnClickListener(v->{            listener.onFoodClick(itemFood);        });        holder.cbFavourite.setVisibility(itemFood.isFavourite() ? View.VISIBLE : View.GONE);    }    @Override    public int getItemCount() {        return itemFoods.size();    }    public class ItemFoodViewHolder extends RecyclerView.ViewHolder {        ImageView imageView;        TextView tvName;        TextView tvRate;        TextView tvTime;        CheckBox cbFavourite;        public ItemFoodViewHolder(@NonNull View itemView){            super(itemView);            imageView = itemView.findViewById(R.id.image_item_food);            tvName = itemView.findViewById(R.id.tv_name_item_food);            tvRate = itemView.findViewById(R.id.tv_rate);            tvTime = itemView.findViewById(R.id.tv_time_finish_item);            cbFavourite = itemView.findViewById(R.id.checkbox_favourite_item_food);        }    }}